package dev.harrison.rendacomcarro.operation.domain;
import jakarta.persistence.*; import java.math.BigDecimal; import java.time.LocalDate; import java.util.UUID;
@Entity @Table(name="revenue") public class Revenue { @Id private UUID id; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="shift_id",nullable=false) private Shift shift; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="trip_id") private Trip trip; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="platform_id") private Platform platform; @Enumerated(EnumType.STRING) private RevenueType type; @Column(name="competence_date") private LocalDate competenceDate; @Column(name="received_date") private LocalDate receivedDate; @Column(name="gross_amount") private BigDecimal grossAmount; @Column(name="platform_fee") private BigDecimal platformFee; @Column(name="net_amount") private BigDecimal netAmount; @Column(name="tip_amount") private BigDecimal tipAmount; @Column(name="bonus_amount") private BigDecimal bonusAmount; @Enumerated(EnumType.STRING) private DataSource source; private String notes; protected Revenue(){} public UUID getId(){return id;} }
